18: pub fn tokenize(input: &str) -> Vec<Token> {
19:     let chars: Vec<char> = input.chars().collect();
20:     let mut tokens = Vec::new();
21:     let mut i = 0;
22:     while i < chars.len() {
23:         match chars[i] {
24:             ' ' | '\t' => { i += 1; }
25:             '+' => { tokens.push(Token::Plus); i += 1; }
26:             '-' => { tokens.push(Token::Minus); i += 1; }
27:             '*' => { tokens.push(Token::Star); i += 1; }
28:             '/' => { tokens.push(Token::Slash); i += 1; }
29:             '=' => { tokens.push(Token::Eq); i += 1; }
30:             '>' => { tokens.push(Token::Gt); i += 1; }
31:             '<' => { tokens.push(Token::Lt); i += 1; }
32:             '!' => { tokens.push(Token::Bang); i += 1; }
33:             c if c.is_ascii_digit() || c == '.' => {
34:                 let start = i;
35:                 while i < chars.len() && (chars[i].is_ascii_digit() || chars[i] == '.') {
36:                     i += 1;
37:                 }
38:                 let num: f64 = input[start..i].parse().unwrap();
39:                 tokens.push(Token::Number(num));
40:             }
